// The COMMANDS array above is the authoritative dispatch table. These aliases
// allow tooling and tests to discover command handlers by name independently.
const HANDLERS = {};
HANDLERS.skills = cmdSkills;
HANDLERS.approval = cmdApproval;
HANDLERS.web = cmdWeb;
HANDLERS.mcp = cmdMcp;
HANDLERS.subagents = cmdSubagents;
HANDLERS.exec = cmdExec;
HANDLERS.image = cmdImage;
HANDLERS.review = cmdReview;

if(typeof window!=='undefined'){
  const _origActionChipClick=window.actionChipClick;
  window.actionChipClick=function(cmd){
    const command=String(cmd||'').trim();
    if(command==='/review'){
      void cmdReview('');
      return;
    }
    if(command.startsWith('/browser')){
      void cmdBrowser(command.slice('/browser'.length).trim());
      return;
    }
    if(typeof _origActionChipClick==='function'){
      return _origActionChipClick(cmd);
    }
  };
}


